/*
Tasker Status Banner Tooltip badge that looks like a pill
STRY0101803 - added status badge to correct what the popup was setting for status
2.7.0 | 2021-08-23 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
  Put into a style sheet
*/

.Projected.on.time {
  background-color:  $success;
  color: $brand-success-text;
}

.Warning {
  background-color:  $warning;
  color: $brand-warning-text;
}

.Critical {
  background-color:  $danger;
  color: $brand-danger-text;
}
